import{_ as s,r as i,h as o,c as d,a as r,I as p,d as l,F as c,u as g,o as u}from"./index-CUZyDM3j.js";const n={__name:"Guide",setup(f){return g(),i(""),o(async()=>{}),(e,a)=>{const t=l;return u(),d(c,null,[r(t,{title:e.$t("guideTitle"),"left-arrow":""},null,8,["title"]),a[0]||(a[0]=p('<div class="guide-container" data-v-748fa5be><div class="guide-container-content" data-v-748fa5be><h2 class="guide-title" data-v-748fa5be>1. How to Register</h2><p class="guide-step" data-v-748fa5be>- <span class="step-highlight" data-v-748fa5be>Step.1</span> Fill Your Phone Number and Receive verification code</p><p class="guide-step" data-v-748fa5be>- <span class="step-highlight" data-v-748fa5be>Step.2</span> Set Your Own Password (8 letters)</p><p class="guide-step" data-v-748fa5be>- <span class="step-highlight" data-v-748fa5be>Step.3</span> Confirm The Password</p><p class="guide-step" data-v-748fa5be>- <span class="step-highlight" data-v-748fa5be>Step.4</span> Fill Your Recommendation Code</p><p class="guide-step" data-v-748fa5be>- <span class="step-highlight" data-v-748fa5be>Step.5</span> Click &quot;I Have Read And Agree&quot;</p><p class="guide-step" data-v-748fa5be>- Click &quot;<span class="step-highlight" data-v-748fa5be>Register</span>&quot; to successfully join us!</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153522ddfv.png" alt="Register Guide" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>2. How to Betting</h2><p class="guide-text" data-v-748fa5be>Click start game then choose 1 minute, 3 minute, 5 minute or 10 minute.</p><p class="guide-text" data-v-748fa5be>Green: if the result shows 1,3,7,9</p><p class="guide-text" data-v-748fa5be>Red: if the result shows 2,4,6,8</p><p class="guide-text" data-v-748fa5be>Violet: if the result shows 0 or 5</p><p class="guide-text" data-v-748fa5be>Small: if the result shows 0,1,2,3,4</p><p class="guide-text" data-v-748fa5be>Big: if the result shows 5,6,7,8,9</p><p class="guide-text guide-warning" data-v-748fa5be>This company not allowed to place Illegal betting<br data-v-748fa5be>Exp: Betting (Big and small together) or (Red and Green together) in the same time.</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_202505111535404aer.png" alt="Betting Guide" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>3. How to Recharge</h2><p class="guide-text" data-v-748fa5be>Click Wallet Icon, Click The Deposit Button, and we have five ways to make a recharge (BANK TRANSFER, E-WALLET)</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153554e5iq.jpg" alt="Recharge Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_2025051115360376vr.jpg" alt="Recharge Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>4. How to Withdraw</h2><p class="guide-text" data-v-748fa5be>Click Wallet Icon, Click Withdraw Button.</p><p class="guide-step" data-v-748fa5be>- Enter withdraw amount</p><p class="guide-step" data-v-748fa5be>- Make Sure Your Total Bet Until Zero</p><p class="guide-step" data-v-748fa5be>- Select Your Bank Account Or Add Your Bank Account</p><p class="guide-step" data-v-748fa5be>- Input Amount You Want To Withdraw</p><p class="guide-step" data-v-748fa5be>- Input Your Login Password</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153758c719.jpg" alt="Withdraw Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153806743v.jpg" alt="Withdraw Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>5. Orders</h2><p class="guide-text" data-v-748fa5be>When The Betting Complete You Can Click My Game History To See Your Bet Record, You Can Check The Chart Trend.</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153834gl4j.jpg" alt="Orders Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_202505111538434bod.jpg" alt="Orders Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>6. Promotion</h2><p class="guide-text" data-v-748fa5be>- If you have a downline or referral member use your own link to register and if they make a recharge you can claim a reward. The agent will get a minimum commission of 0.6% (level 1) and 0.18% (level 2) from each transaction that is done by the referral (Added every day at 00:30 AM.) If the accumulated transactions of the Referral reach a certain target, the agent will get an additional bonus with the following rebates.</p><p class="guide-step" data-v-748fa5be>- You Can Click Invitation Link To See The Barcode</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153930art9.png" alt="Promotion Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511153938ea8a.png" alt="Promotion Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>7. Account Security</h2><p class="guide-text" data-v-748fa5be>Go To Profile Icon, Click Setting Icon.</p><p class="guide-step" data-v-748fa5be>- Click Login Password.</p><p class="guide-step" data-v-748fa5be>- Re-Enter Your Login Password.</p><p class="guide-step" data-v-748fa5be>- Enter Strongest New Password, and Confirm Your Password.</p><p class="guide-step" data-v-748fa5be>- Click Save Changes.</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154104hk99.jpg" alt="Security Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154137t5tv.jpg" alt="Security Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>8. Forgot Password</h2><p class="guide-step" data-v-748fa5be>- If You Forget Your Login Password, Please Contact Customer Service Immediately.</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154228n6ak.png" alt="Forgot Password Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154241w4o6.jpg" alt="Forgot Password Guide 2" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>9. App Download</h2><p class="guide-text" data-v-748fa5be>Click Add To Desktop icon, you can download the app and it&#39;s easy to use</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_202505111542577mei.jpg" alt="App Download Guide" data-v-748fa5be></div><h2 class="guide-title" data-v-748fa5be>10. Gift</h2><p class="guide-step" data-v-748fa5be>- Click Gifts</p><p class="guide-step" data-v-748fa5be>- Input The Unique Code To Redemption Code The Money</p><p class="guide-step" data-v-748fa5be>- Click Receive</p><div class="guide-images" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154353kipy.jpg" alt="Gift Guide 1" data-v-748fa5be><img src="https://ossimg.forpicStore777.top/rajalottery/editor/editor_20250511154400t9hs.jpg" alt="Gift Guide 2" data-v-748fa5be></div></div></div>',1))],64)}}},h=s(n,[["__scopeId","data-v-748fa5be"]]);export{h as default};
